#include <iostream>
#include <iomanip>
#include <cmath>

int main() {
    const double pi = 3.141592;
    double C;
    std::cin >> C;
    // C = 2 * pi * r  =>  r = C / (2 * pi)
    // Area = pi * r * r = pi * (C / (2*pi))^2 = C * C / (4 * pi)
    double area = (C * C) / (4.0 * pi);
    std::cout << std::fixed << std::setprecision(4) << area << std::endl;
    return 0;
}
